import { readFileSync, existsSync, writeFileSync, mkdirSync } from 'node:fs';

console.log('[run-windows-upgrade-harness] Windows Desktop Upgrade Harness Collector...');

const commitSha = process.env.COMMIT_SHA || process.env.GITHUB_SHA;
const runId = String(process.env.RUN_ID || process.env.GITHUB_RUN_ID || '');

mkdirSync('results', { recursive: true });

// HARD SAFETY RULE:
// No synthetic success events. No literal string hashing.
// Harness MUST consume actual raw evidence files generated by real Windows process automation.
const rawEvidenceFiles = [
  'raw_evidence/previous-install.json',
  'raw_evidence/updater-events.jsonl',
  'raw_evidence/downloaded-asset.json',
  'raw_evidence/installer-process.json',
  'raw_evidence/relaunch-version.json',
  'raw_evidence/post-upgrade-smoke.json',
];

let isRawEvidencePresent = true;
const rawData = {};

for (const rawFile of rawEvidenceFiles) {
  if (!existsSync(rawFile)) {
    isRawEvidencePresent = false;
    break;
  }
  try {
    const content = readFileSync(rawFile, 'utf8');
    rawData[rawFile] = rawFile.endsWith('.jsonl') ? content.split('\n').filter(Boolean) : JSON.parse(content);
  } catch (e) {
    isRawEvidencePresent = false;
    break;
  }
}

if (!isRawEvidencePresent) {
  console.log('STATUS: DESKTOP UPGRADE RUNNER: BLOCKED');
  console.log('Reason: No raw Windows process execution evidence found in raw_evidence/. Upgrade test requires real Windows runner (runs-on: [self-hosted, windows, mydesck-upgrade-test]).');

  const blockedResult = {
    test: 'desktop-upgrade',
    status: 'BLOCKED',
    commit_sha: commitSha || 'unbound',
    workflow_run_id: runId || 'unbound',
    timestamp: new Date().toISOString(),
    details: 'Physical Windows NSIS update download, launch, relaunch, and post-upgrade data persistence not observed on runner yet.'
  };
  writeFileSync('results/desktop-upgrade-result.json', JSON.stringify(blockedResult, null, 2), 'utf8');
  process.exit(1);
}

// Consuming Observed Raw Evidence (Only when created by real runner automation)
const prevInstall = rawData['raw_evidence/previous-install.json'];
const downloaded = rawData['raw_evidence/downloaded-asset.json'];
const proc = rawData['raw_evidence/installer-process.json'];
const relaunch = rawData['raw_evidence/relaunch-version.json'];
const smoke = rawData['raw_evidence/post-upgrade-smoke.json'];

if (!prevInstall?.installed_previous_version || 
    !downloaded?.downloaded_asset_sha256 || 
    proc?.installer_process_exit_code !== 0 || 
    !relaunch?.relaunched_version ||
    smoke?.save_trip_result !== 'PASS' || 
    smoke?.edit_trip_result !== 'PASS') {
  console.error('❌ RAW EVIDENCE INCOMPLETE OR INVALID');
  const failResult = {
    test: 'desktop-upgrade',
    status: 'FAIL',
    commit_sha: commitSha,
    workflow_run_id: runId,
    timestamp: new Date().toISOString(),
    details: 'Raw process evidence contained failed or missing stage verifications.'
  };
  writeFileSync('results/desktop-upgrade-result.json', JSON.stringify(failResult, null, 2), 'utf8');
  process.exit(1);
}

const candidateVersion = JSON.parse(readFileSync('package.json', 'utf8')).version;

const upgradeResult = {
  test: 'desktop-upgrade',
  status: 'STAGING PASS',
  commit_sha: commitSha,
  workflow_run_id: runId,
  timestamp: new Date().toISOString(),
  previous_version: prevInstall.installed_previous_version,
  candidate_version: candidateVersion,
  installed_previous_version: prevInstall.installed_previous_version,
  detected_candidate_version: candidateVersion,
  downloaded_asset_sha256: downloaded.downloaded_asset_sha256,
  installer_process_exit_code: proc.installer_process_exit_code,
  relaunched_version: relaunch.relaunched_version,
  save_trip_result: smoke.save_trip_result,
  edit_trip_result: smoke.edit_trip_result,
  test_machine_id: process.env.RUNNER_NAME || 'windows-test-vm-01',
  evidence_session_id: downloaded.session_id || 'session-001',
  sanitized_updater_log: 'sanitized-updater.log',
  details: 'Observed automated Windows desktop upgrade verified from raw evidence files.'
};

writeFileSync('results/desktop-upgrade-result.json', JSON.stringify(upgradeResult, null, 2), 'utf8');
console.log('✓ Observed Automated Windows Desktop Upgrade Evidence Verified and Saved.');
